import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import api from '../../api/axiosInstance';
import Navbar from '../../components/Navbar';
import styles from './UserPages.module.css';

const DashboardPage = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState({ packages: 0, bookings: 0, destinations: 0 });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const [pkgs, bkgs, dests] = await Promise.all([
          api.get('/packages'),
          api.get('/bookings'),
          api.get('/destinations'),
        ]);
        setStats({
          packages:     pkgs.data?.data?.length    ?? 0,
          bookings:     bkgs.data?.data?.length    ?? 0,
          destinations: dests.data?.data?.length   ?? 0,
        });
      } catch {
        // silently fail – stats unavailable
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  return (
    <>
      <Navbar />
      <div className={styles.page}>
        <h1>Welcome back 👋</h1>
        <p className={styles.sub}>Here's a quick overview of your account.</p>

        {loading ? (
          <p>Loading stats…</p>
        ) : (
          <div className={styles.grid}>
            <StatCard icon="✈️" label="Packages"     value={stats.packages}     to="/packages" />
            <StatCard icon="📅" label="My Bookings"  value={stats.bookings}     to="/bookings" />
            <StatCard icon="📍" label="Destinations" value={stats.destinations} to="/destinations" />
          </div>
        )}
      </div>
    </>
  );
};

const StatCard = ({ icon, label, value, to }) => (
  <Link to={to} className={styles.statCard}>
    <span className={styles.statIcon}>{icon}</span>
    <span className={styles.statValue}>{value}</span>
    <span className={styles.statLabel}>{label}</span>
  </Link>
);

export default DashboardPage;
